/**
 * Deploy DeterministicRiskModel to PVM on Polkadot Hub TestNet.
 *
 * Uses pre-built PVM artifact from pvm-artifacts/DeterministicRiskModel.json
 * (generated by `npm run build:pvm`). Does not invoke hardhat compilation.
 *
 * Usage:
 *   cd dualvm && node scripts/deploy-deterministic-risk-model-pvm.mjs
 */

import { ethers } from "ethers";
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { ApiPromise, WsProvider } from "@polkadot/api";
import { hexToU8a } from "@polkadot/util";
import { encodeAddress } from "@polkadot/util-crypto";
import { formatUnits } from "viem";
import * as dotenv from "dotenv";

dotenv.config();

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const cwd = path.join(__dirname, "..");

// ---- Load artifacts and manifests -----------------------------------------------

const artifactPath = path.join(cwd, "pvm-artifacts", "DeterministicRiskModel.json");
const artifact = JSON.parse(readFileSync(artifactPath, "utf8"));
if (!artifact.bytecode || !artifact.abi) {
  throw new Error(`Invalid PVM artifact at ${artifactPath}. Run 'npm run build:pvm' first.`);
}

const canonicalManifest = JSON.parse(
  readFileSync(path.join(cwd, "deployments", "polkadot-hub-testnet-canonical.json"), "utf8"),
);

const probesManifestPath = path.join(cwd, "deployments", "polkadot-hub-testnet-probes.json");
const probesManifest = JSON.parse(readFileSync(probesManifestPath, "utf8"));

// ---- Environment ---------------------------------------------------------------

const PRIVATE_KEY = process.env.PRIVATE_KEY;
if (!PRIVATE_KEY) throw new Error("Missing required environment variable: PRIVATE_KEY");

const RPC_URL =
  process.env.POLKADOT_HUB_TESTNET_RPC_FALLBACK_URL ??
  canonicalManifest.polkadotHubTestnet.fallbackRpcUrl ??
  "https://services.polkadothub-rpc.com/testnet/";

const WSS_URL = probesManifest.polkadotHubTestnet.wssUrl ?? "wss://asset-hub-paseo-rpc.n.dwellir.com";

// ---- Helpers --------------------------------------------------------------------

function evmToFallbackAccountHex(address) {
  const normalized = address.slice(2).toLowerCase();
  return `0x${normalized}${"ee".repeat(12)}`;
}

function fallbackAccountHexToSs58(accountHex) {
  return encodeAddress(hexToU8a(accountHex), 0);
}

async function readContractCodeHash(api, address) {
  const info = await api.query.revive.accountInfoOf(address);
  if (!info.isSome) return undefined;
  const json = info.unwrap().toJSON();
  return json?.accountType?.contract?.codeHash;
}

async function readFallbackAccountBalance(api, accountHex) {
  const account = await api.query.system.account(accountHex);
  return BigInt(account.data.free.toString());
}

// ---- Standard quote inputs (matches VAL-PVM-002 test inputs) --------------------

const STANDARD_QUOTE_INPUT = [
  5000,   // utilizationBps: 50%
  15000,  // collateralRatioBps: 150% (healthy, > stressedCollateralRatioBps=14000)
  0,      // oracleAgeSeconds
  true,   // oracleFresh
];

const EXPECTED_OUTPUT = {
  borrowRateBps: 700n,
  maxLtvBps: 7500n,
  liquidationThresholdBps: 8500n,
};

// ---- Main -----------------------------------------------------------------------

async function main() {
  const provider = new ethers.JsonRpcProvider(RPC_URL);
  const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

  const evmAddress = wallet.address;
  const fallbackAccountHex = evmToFallbackAccountHex(evmAddress);
  const paseoSs58 = fallbackAccountHexToSs58(fallbackAccountHex);

  console.log(JSON.stringify({ deployer: evmAddress, rpcUrl: RPC_URL }, null, 2));

  // Check PAS balance via substrate API
  const api = await ApiPromise.create({ provider: new WsProvider(WSS_URL) });
  await api.isReady;

  try {
    const balanceWei = await readFallbackAccountBalance(api, fallbackAccountHex);
    const balancePas = formatUnits(balanceWei, 18);
    console.log(JSON.stringify({ balancePas, balanceWei: balanceWei.toString() }, null, 2));

    if (balanceWei === 0n) {
      throw new Error(`Deployer ${evmAddress} has 0 PAS. Fund via https://faucet.polkadot.io/`);
    }

    // ---- Build constructor args from canonical manifest's riskEngine config ----
    const rc = canonicalManifest.config.riskEngine;
    const constructorArgs = [
      BigInt(rc.baseRateBps),
      BigInt(rc.slope1Bps),
      BigInt(rc.slope2Bps),
      BigInt(rc.kinkBps),
      BigInt(rc.healthyMaxLtvBps),
      BigInt(rc.stressedMaxLtvBps),
      BigInt(rc.healthyLiquidationThresholdBps),
      BigInt(rc.stressedLiquidationThresholdBps),
      BigInt(rc.staleBorrowRatePenaltyBps),
      BigInt(rc.stressedCollateralRatioBps),
    ];

    console.log(
      JSON.stringify(
        {
          step: "Deploying DeterministicRiskModel to PVM testnet",
          constructorArgs: constructorArgs.map(String),
        },
        null,
        2,
      ),
    );

    // ---- Deploy using pre-built PVM bytecode ------------------------------------
    const factory = new ethers.ContractFactory(artifact.abi, artifact.bytecode, wallet);
    const contract = await factory.deploy(...constructorArgs);
    await contract.waitForDeployment();

    const deployTx = contract.deploymentTransaction();
    if (!deployTx) throw new Error("Missing deployment transaction");

    const pvmAddress = await contract.getAddress();
    const explorerBaseUrl = probesManifest.polkadotHubTestnet.explorerUrl;

    console.log(
      JSON.stringify(
        {
          step: "Deployment confirmed",
          pvmAddress,
          deployTxHash: deployTx.hash,
          explorerUrl: `${explorerBaseUrl}address/${pvmAddress}`,
        },
        null,
        2,
      ),
    );

    // ---- Verify via revive.accountInfoOf (confirms PVM code hash) ---------------
    const codeHash = await readContractCodeHash(api, pvmAddress);
    if (!codeHash) {
      throw new Error(
        `DeterministicRiskModel deployed at ${pvmAddress} but revive.accountInfoOf returned no code hash.`,
      );
    }

    console.log(JSON.stringify({ step: "PVM code hash verified", codeHash }, null, 2));

    // ---- Call quote() on PVM contract and EVM riskEngine -------------------------
    const evmRiskEngineAddress = canonicalManifest.contracts.riskEngine;
    const pvmContract = new ethers.Contract(pvmAddress, artifact.abi, provider);
    const evmContract = new ethers.Contract(evmRiskEngineAddress, artifact.abi, provider);

    console.log(
      JSON.stringify(
        {
          step: "Calling quote() on both PVM and EVM contracts",
          pvmAddress,
          evmAddress: evmRiskEngineAddress,
          inputs: STANDARD_QUOTE_INPUT,
        },
        null,
        2,
      ),
    );

    const pvmResult = await pvmContract.quote(STANDARD_QUOTE_INPUT);
    const evmResult = await evmContract.quote(STANDARD_QUOTE_INPUT);

    const pvmQuote = {
      borrowRateBps: BigInt(pvmResult[0]),
      maxLtvBps: BigInt(pvmResult[1]),
      liquidationThresholdBps: BigInt(pvmResult[2]),
    };
    const evmQuote = {
      borrowRateBps: BigInt(evmResult[0]),
      maxLtvBps: BigInt(evmResult[1]),
      liquidationThresholdBps: BigInt(evmResult[2]),
    };

    const quotesMatch =
      pvmQuote.borrowRateBps === evmQuote.borrowRateBps &&
      pvmQuote.maxLtvBps === evmQuote.maxLtvBps &&
      pvmQuote.liquidationThresholdBps === evmQuote.liquidationThresholdBps;

    const pvmMatchesExpected =
      pvmQuote.borrowRateBps === EXPECTED_OUTPUT.borrowRateBps &&
      pvmQuote.maxLtvBps === EXPECTED_OUTPUT.maxLtvBps &&
      pvmQuote.liquidationThresholdBps === EXPECTED_OUTPUT.liquidationThresholdBps;

    console.log(
      JSON.stringify(
        {
          step: "Quote comparison",
          pvmQuote: {
            borrowRateBps: pvmQuote.borrowRateBps.toString(),
            maxLtvBps: pvmQuote.maxLtvBps.toString(),
            liquidationThresholdBps: pvmQuote.liquidationThresholdBps.toString(),
          },
          evmQuote: {
            borrowRateBps: evmQuote.borrowRateBps.toString(),
            maxLtvBps: evmQuote.maxLtvBps.toString(),
            liquidationThresholdBps: evmQuote.liquidationThresholdBps.toString(),
          },
          quotesMatch,
          pvmMatchesExpected,
        },
        null,
        2,
      ),
    );

    if (!quotesMatch) {
      throw new Error(
        `Quote mismatch: PVM returned ${JSON.stringify(pvmQuote)} but EVM returned ${JSON.stringify(evmQuote)}`,
      );
    }
    if (!pvmMatchesExpected) {
      throw new Error(
        `PVM quote does not match expected: got ${JSON.stringify(pvmQuote)}, expected ${JSON.stringify(EXPECTED_OUTPUT)}`,
      );
    }

    // ---- Update probes manifest --------------------------------------------------
    probesManifest.pvm.deterministicRiskModel = {
      address: pvmAddress,
      deployTxHash: deployTx.hash,
      explorerUrl: `${explorerBaseUrl}address/${pvmAddress}`,
      codeHash,
    };

    const notePrefix = "DeterministicRiskModel (PVM) deployed by";
    probesManifest.notes = [
      ...(probesManifest.notes ?? []).filter((n) => !n.startsWith(notePrefix)),
      `${notePrefix} ${evmAddress} at ${pvmAddress}. quote() verified identical to EVM riskEngine ${evmRiskEngineAddress}. Inputs: utilization=5000bps, collateralRatio=15000bps, oracleFresh=true. Output: borrowRate=700bps, maxLtv=7500bps, liqThreshold=8500bps.`,
    ];

    probesManifest.generatedAt = new Date().toISOString();
    writeFileSync(probesManifestPath, JSON.stringify(probesManifest, null, 2));

    console.log(
      JSON.stringify(
        {
          result: "SUCCESS",
          pvmDeterministicRiskModel: probesManifest.pvm.deterministicRiskModel,
          quoteVerification: "PASSED: PVM == EVM for standard test inputs",
          manifestUpdated: probesManifestPath,
        },
        null,
        2,
      ),
    );
  } finally {
    await api.disconnect();
  }
}

main().catch((err) => {
  console.error(err);
  process.exitCode = 1;
});
